com.mirth.connect.plugins.javascriptstep.script:
var patientId = msg['PID']['PID.3']['PID.3.1'].toString();
var lastName = msg['PID']['PID.5']['PID.5.1'].toString();
var firstName = msg['PID']['PID.5']['PID.5.2'].toString();
var dob = msg['PID']['PID.7']['PID.7.1'].toString();
var gender = msg['PID']['PID.8']['PID.8.1'].toString();
var messageControlId =
    msg['MSH']['MSH.10']['MSH.10.1'].toString();

var messageCode =
    msg['MSH']['MSH.9']['MSH.9.1'].toString();

var triggerEvent =
    msg['MSH']['MSH.9']['MSH.9.2'].toString();

var messageType =
    messageCode + '^' + triggerEvent;

var visitId = '';

if (msg['PV1']['PV1.19']['PV1.19.1'].toString() != '') {
    visitId = msg['PV1']['PV1.19']['PV1.19.1'].toString();
} else {
    visitId = msg['PV1']['PV1.18']['PV1.18.1'].toString();
}
var location = msg['PV1']['PV1.3']['PV1.3.1'].toString();
var patientClass = msg['PV1']['PV1.2']['PV1.2.1'].toString();
var provider = msg['PV1']['PV1.7']['PV1.7.2'].toString();

var kinLastName = msg['NK1']['NK1.2']['NK1.2.1'].toString();
var kinFirstName = msg['NK1']['NK1.2']['NK1.2.2'].toString();
var kinRelationship = msg['NK1']['NK1.3']['NK1.3.1'].toString();
var kinAddress = msg['NK1']['NK1.4']['NK1.4.1'].toString();
var kinPhone = msg['NK1']['NK1.5']['NK1.5.1'].toString();

var allergyCode = msg['AL1']['AL1.3']['AL1.3.1'].toString();
var allergyDescription = msg['AL1']['AL1.3']['AL1.3.2'].toString();
var allergySeverity = msg['AL1']['AL1.4']['AL1.4.1'].toString();
var allergyReaction = msg['AL1']['AL1.5']['AL1.5.1'].toString();

var diagnosisCode = msg['DG1']['DG1.3']['DG1.3.1'].toString();
var diagnosisDescription = msg['DG1']['DG1.3']['DG1.3.2'].toString();
var diagnosisType = msg['DG1']['DG1.6']['DG1.6.1'].toString();

channelMap.put('patient_id', patientId);
channelMap.put('last_name', lastName);
channelMap.put('first_name', firstName);
channelMap.put('dob', dob);
channelMap.put('gender', gender);
channelMap.put('visit_id', visitId);
channelMap.put('location', location);
channelMap.put('patient_class', patientClass);
channelMap.put('provider', provider);

channelMap.put('kin_last_name', kinLastName);
channelMap.put('kin_first_name', kinFirstName);
channelMap.put('kin_relationship', kinRelationship);
channelMap.put('kin_address', kinAddress);
channelMap.put('kin_phone', kinPhone);

channelMap.put('allergy_code', allergyCode);
channelMap.put('allergy_description', allergyDescription);
channelMap.put('allergy_severity', allergySeverity);
channelMap.put('allergy_reaction', allergyReaction);

channelMap.put('diagnosis_code', diagnosisCode);
channelMap.put('diagnosis_description', diagnosisDescription);
channelMap.put('diagnosis_type', diagnosisType);

channelMap.put(
    'message_control_id',
    messageControlId
);

channelMap.put(
    'message_type',
    messageType
);

channelMap.put(
    'received_at',
    DateUtil.getCurrentDate('yyyy-MM-dd HH:mm:ss')
);

var validationErrors = [];

// Retrieve the values extracted by the previous step
var patientId = $('patient_id');
var visitId = $('visit_id');
var firstName = $('first_name');
var lastName = $('last_name');
var dob = $('dob');
var gender = $('gender');
var patientClass = $('patient_class');
var location = $('location');
var provider = $('provider');
var allergyCode = $('allergy_code');
var diagnosisCode = $('diagnosis_code');

// -------------------------
// Required-field validation
// -------------------------

if (!patientId || patientId.toString().trim() === '') {
    validationErrors.push('PID-3 Patient ID is missing');
}

if (!visitId || visitId.toString().trim() === '') {
    validationErrors.push('PV1-19 Visit ID is missing');
}

if (!firstName || firstName.toString().trim() === '') {
    validationErrors.push('PID-5.2 First name is missing');
}

if (!lastName || lastName.toString().trim() === '') {
    validationErrors.push('PID-5.1 Last name is missing');
}

if (!dob || dob.toString().trim() === '') {
    validationErrors.push('PID-7 Date of birth is missing');
}

if (!gender || gender.toString().trim() === '') {
    validationErrors.push('PID-8 Gender is missing');
}

if (!patientClass || patientClass.toString().trim() === '') {
    validationErrors.push('PV1-2 Patient class is missing');
}

if (!location || location.toString().trim() === '') {
    validationErrors.push('PV1-3 Location is missing');
}

if (!provider || provider.toString().trim() === '') {
    validationErrors.push('PV1-7 Provider is missing');
}

if (!allergyCode || allergyCode.toString().trim() === '') {
    validationErrors.push('AL1-3 Allergy code is missing');
}

if (!diagnosisCode || diagnosisCode.toString().trim() === '') {
    validationErrors.push('DG1-3 Diagnosis code is missing');
}

// -------------------------
// Format validation
// -------------------------

if (patientId && !/^\d+$/.test(patientId.toString())) {
    validationErrors.push('PID-3 Patient ID must contain digits only');
}

if (visitId && !/^\d+$/.test(visitId.toString())) {
    validationErrors.push('PV1-19 Visit ID must contain digits only');
}

if (dob && !/^\d{8}$/.test(dob.toString())) {
    validationErrors.push('PID-7 DOB must use YYYYMMDD format');
}

// Convert Mirth/Java values into normal JavaScript strings
var normalisedGender =
    gender == null ? '' : String(gender).replace(/^\s+|\s+$/g, '').toUpperCase();

var normalisedPatientClass =
    patientClass == null
        ? ''
        : String(patientClass).replace(/^\s+|\s+$/g, '').toUpperCase();

// Gender validation
if (
    normalisedGender !== '' &&
    normalisedGender !== 'M' &&
    normalisedGender !== 'F' &&
    normalisedGender !== 'O' &&
    normalisedGender !== 'U'
) {
    validationErrors.push(
        'PID-8 Gender must be M, F, O, or U. Received: [' +
        normalisedGender +
        ']'
    );
}

// Patient class validation
if (
    normalisedPatientClass !== '' &&
    normalisedPatientClass !== 'I' &&
    normalisedPatientClass !== 'O' &&
    normalisedPatientClass !== 'E'
) {
    validationErrors.push(
        'PV1-2 Patient class must be I, O, or E. Received: [' +
        normalisedPatientClass +
        ']'
    );
}

// -------------------------
// Reject invalid messages
// -------------------------

if (validationErrors.length > 0) {

    var errorMessage =
        'HL7 validation failed: ' +
        validationErrors.join('; ');

    var safeErrorMessage = String(errorMessage)
        .replace(/\u0000/g, '')
        .trim();

    channelMap.put('validation_status', 'FAILED');
    channelMap.put('validation_errors', safeErrorMessage);

    var logConn = null;

    try {
        logConn =
            DatabaseConnectionFactory.createDatabaseConnection(
                'com.mysql.cj.jdbc.Driver',
                'jdbc:mysql://localhost:3306/demoehr_receiver',
                'root',
                '-----------'
            );

        var logSql =
            "INSERT INTO IntegrationLog " +
            "(" +
                "message_control_id, " +
                "message_type, " +
                "patient_id, " +
                "visit_id, " +
                "validation_status, " +
                "duplicate_flag, " +
                "processing_status, " +
                "ack_code, " +
                "error_Message, " +
                "received_at, " +
                "completed_at, " +
                "channel_name" +
            ") " +
            "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), ?)";

     logger.info("message_control_id = " + $('message_control_id'));
	logger.info("message_type = " + $('message_type'));
	logger.info("patientId = " + patientId);
	logger.info("visitId = " + visitId);
	logger.info("safeErrorMessage = " + safeErrorMessage);
	logger.info("received_at = " + $('received_at'));

        logConn.executeUpdate(logSql, [
            $('message_control_id'),
            $('message_type'),

            patientId === '' ? null : patientId,
            visitId === '' ? null : visitId,

            'FAILED',
            0,
            'VALIDATION_FAILED',
            'AE',
            safeErrorMessage,
            new java.sql.Timestamp(new Date().getTime()),
            'ADT_Inbound_Receiver'
        ]);

    } catch (logError) {

        logger.error(
            'Could not write validation failure to IntegrationLog: ' +
            logError
        );

    } finally {

        if (logConn != null) {
            logConn.close();
        }
    }

    logger.error(safeErrorMessage);

    throw safeErrorMessage;
}

var dbConn = null;

try {
    var visitId = String($('visit_id'))
        .replace(/^\s+|\s+$/g, '');

    var messageControlId = '';

    if (
        msg['MSH'] &&
        msg['MSH']['MSH.10'] &&
        msg['MSH']['MSH.10']['MSH.10.1']
    ) {
        messageControlId =
            msg['MSH']['MSH.10']['MSH.10.1'].toString();
    }

    dbConn = DatabaseConnectionFactory.createDatabaseConnection(
        'com.mysql.cj.jdbc.Driver',
        'jdbc:mysql://localhost:3306/demoehr_receiver',
        'root',
        '----------'
    );

    var sql =
        'SELECT COUNT(*) AS duplicate_count ' +
        'FROM Encounters ' +
        'WHERE visitid = ?';

    var result = dbConn.executeCachedQuery(
        sql,
        [visitId]
    );

    var duplicateCount = 0;

    if (result.next()) {
        duplicateCount = result.getInt('duplicate_count');
    }

    result.close();

    if (duplicateCount > 0) {
        channelMap.put('is_duplicate', 'true');
        channelMap.put(
            'duplicate_reason',
            'Visit ID ' + visitId +
            ' already exists in Hospital B'
        );

        logger.warn(
            'Duplicate HL7 message detected. ' +
            'Visit ID=' + visitId +
            ', Message Control ID=' + messageControlId
        );
    } else {
        channelMap.put('is_duplicate', 'false');
        channelMap.put('duplicate_reason', '');

        logger.info(
            'No duplicate found. Visit ID=' +
            visitId +
            ', Message Control ID=' +
            messageControlId
        );
    }

    channelMap.put(
        'message_control_id',
        messageControlId
    );

} finally {
    if (dbConn != null) {
        dbConn.close();
    }
}

properties.script:
var dbConn = DatabaseConnectionFactory.createDatabaseConnection(
    'com.mysql.cj.jdbc.Driver',
    'jdbc:mysql://localhost:3306/demoehr_receiver',
    'root',
    '----------'
);

var sql = "INSERT INTO PatientDemographics " +
"(patientid, dob, gender, race, ethnicity, address, city, state, postcode, phone) " +
"VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)";

dbConn.executeUpdate(sql, [
    $('patient_id'),
    $('dob'),
    $('gender'),
    '',
    '',
    $('address'),
    $('city'),
    $('state'),
    $('postcode'),
    $('phone')
]);

dbConn.close();

var dbConn = DatabaseConnectionFactory.createDatabaseConnection(
    'com.mysql.cj.jdbc.Driver',
    'jdbc:mysql://localhost:3306/demoehr_receiver',
    'root',
    '---------'
);

var sql = "INSERT INTO PatientNames " +
"(patientid, firstname, lastname, middlename) " +
"VALUES (?, ?, ?, ?)";

dbConn.executeUpdate(sql, [
    $('patient_id'),
    $('first_name'),
    $('last_name'),
    ''
]);

dbConn.close();

var dbConn = DatabaseConnectionFactory.createDatabaseConnection(
    'com.mysql.cj.jdbc.Driver',
    'jdbc:mysql://localhost:3306/demoehr_receiver',
    'root',
    '-------'
);

var sql = "INSERT INTO Encounters " +
"(visitid, patientid, encountertype, location, admitdate, dischargedate, provider, processed) " +
"VALUES (?, ?, ?, ?, ?, ?, ?, ?)";

dbConn.executeUpdate(sql, [
    $('visit_id'),
    $('patient_id'),
    $('patient_class'),
    $('location'),
    new java.sql.Timestamp(new Date().getTime()), // admitdate
    null,                                         // dischargedate
    $('provider'),
    1                                             // processed
]);

dbConn.close();

var dbConn = DatabaseConnectionFactory.createDatabaseConnection(
    'com.mysql.cj.jdbc.Driver',
    'jdbc:mysql://localhost:3306/demoehr_receiver',
    'root',
    '--------'
);

var sql = "INSERT INTO NextOfKin " +
"(kinid,patientid, firstname, lastname, relationship, address, phone) " +
"VALUES (?, ?, ?, ?, ?, ?,?)";

dbConn.executeUpdate(sql, [
    $('visit_id'),
    $('patient_id'),
    $('kin_first_name'),
    $('kin_last_name'),
    $('kin_relationship'),
    $('kin_address'),
    $('kin_phone')
]);

dbConn.close();

var dbConn = DatabaseConnectionFactory.createDatabaseConnection(
    'com.mysql.cj.jdbc.Driver',
    'jdbc:mysql://localhost:3306/demoehr_receiver',
    'root',
    '----------'
);

var sql = "INSERT INTO Allergies " +
"(allergyid, patientid, allergy_code, allergy_description, severity, reaction) " +
"VALUES (?, ?, ?, ?, ?, ?)";

dbConn.executeUpdate(sql, [
    $('visit_id'),
    $('patient_id'),
    $('allergy_code'),
    $('allergy_description'),
    $('allergy_severity'),
    $('allergy_reaction')
]);

dbConn.close();

var dbConn = DatabaseConnectionFactory.createDatabaseConnection(
    'com.mysql.cj.jdbc.Driver',
    'jdbc:mysql://localhost:3306/demoehr_receiver',
    'root',
    '---------'
);

var sql = "INSERT INTO Diagnoses " +
"(diagnosisid, visitid, diagnosis_code, diagnosis_description, diagnosis_type) " +
"VALUES (?, ?, ?, ?, ?)";

dbConn.executeUpdate(sql, [
    $('visit_id'),
    $('visit_id'),
    $('diagnosis_code'),
    $('diagnosis_description'),
    $('diagnosis_type')
]);

dbConn.close();

var dbConn = null;

try {

    dbConn =
        DatabaseConnectionFactory.createDatabaseConnection(
            'com.mysql.cj.jdbc.Driver',
            'jdbc:mysql://localhost:3306/demoehr_receiver',
            'root',
            '----------'
        );

    var duplicate =
        String($('is_duplicate')) == 'true';

    var duplicateFlag =
        duplicate ? 1 : 0;

    var processingStatus =
        duplicate
            ? 'DUPLICATE_SKIPPED'
            : 'SUCCESS';

    var errorMessage =
        duplicate
            ? String($('duplicate_reason'))
            : '';

    /*
     * A valid new message or an intentionally skipped duplicate
     * is treated as successfully handled, so Hospital B returns AA.
     */
    var ackCode = 'AA';

    var sql =
        "INSERT INTO IntegrationLog " +
        "(" +
            "message_control_id, " +
            "message_type, " +
            "patient_id, " +
            "visit_id, " +
            "validation_status, " +
            "duplicate_flag, " +
            "processing_status, " +
            "ack_code, " +
            "error_message, " +
            "received_at, " +
            "completed_at, " +
            "channel_name" +
        ") " +
        "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), ?)";

    dbConn.executeUpdate(sql, [
        $('message_control_id'),
        $('message_type'),
        $('patient_id'),
        $('visit_id'),
        $('validation_status'),
        duplicateFlag,
        processingStatus,
        ackCode,
        errorMessage,
        $('received_at'),
        'ADT_Inbound_Receiver'
    ]);

    logger.info(
        'Integration audit recorded. ' +
        'Message=' + $('message_control_id') +
        ', Patient=' + $('patient_id') +
        ', Visit=' + $('visit_id') +
        ', Status=' + processingStatus
    );

} catch (e) {

    logger.error(
        'Integration audit logging failed: ' + e
    );

    throw e;

} finally {

    if (dbConn != null) {
        dbConn.close();
    }
}

channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map
return;

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
